import React, { useState, useEffect } from 'react';
import './ImportDataSidebar.css';

function ImportDataSidebar({ jiraData, onSelectUserStory, onClose, isSidebarVisible }) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Function to fetch Jira data
  const fetchJiraData = async () => {
    setLoading(true);
    try {
      const response = await fetch('https://localhost:7216/api/UserStoryDescription/ExportAllUserStories');
      if (!response.ok) {
        throw new Error('Failed to fetch Jira data');
      }
      const data = await response.json();
      console.log('Fetched Jira data:', data);  // Log the full data for verification
      setJiraData(data);  // Set the data in the state
    } catch (err) {
      console.error('Error fetching Jira data:', err);
      setError(`Error fetching Jira data: ${err.message}`);
    } finally {
      setLoading(false);
    }
  };

  // Fetch Jira data when the component mounts
  useEffect(() => {
    fetchJiraData();
  }, []);

  return (
    <div className={`import-sidebar ${isSidebarVisible ? 'visible' : ''}`}>
      <button className="close-btn" onClick={onClose}>X</button>
      <div className="sidebar-title">Imported Jira User Stories</div>

      <div className="jira-stories">
        {jiraData.length === 0 ? (
          <div>No Jira stories found.</div>
        ) : (
          jiraData.map((story) => (
            <div
              key={story.id}  // Using id as the unique identifier
              className="jira-story-box"
              onClick={() => onSelectUserStory(story)}  // Pass the entire story object
            >
              {story.story} {/* Displaying story summary */}
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default ImportDataSidebar;
